UPDATE ai_agents SET system_prompt = system_prompt || E'\n\n=== REGRA CRÍTICA #9 — LINK DE RASTREIO OBRIGATÓRIO ===\nSempre que informar o status de um pacote ou mencionar um código de rastreio, INCLUA o link de rastreio da plataforma com o código já concatenado.\nFormato: https://brfretes.com.br/rastreio/encomenda?codigo=CODIGOAQUI\nExemplo: \"Você pode acompanhar em tempo real aqui: https://brfretes.com.br/rastreio/encomenda?codigo=AD202399246BR\"\n- NUNCA envie o link sem o código concatenado.\n- NUNCA envie apenas o código sem o link.\n- O link deve ser enviado UMA vez por conversa (na primeira menção ao código), não repita em toda mensagem.' WHERE name IN ('felipe', 'veronica') AND is_active = true;